mapper.select:
SELECT A.PROJ_NO , A.EMP_ID , A.PROJ_TTL , A.PROJ_BGNG_DT , A.PROJ_END_DT , A.PROJ_STTS , A.PROJ_DTL , A.PROJ_COLOR , A.PROJ_IPT , A.PROJ_NM , B.PRTPNT_PROJ_IPT , B.PROJ_NO , B.PRTPNT_COLOR , B.PRTPNT_NM , B.PRTPNT_PROJ_IPT , (SELECT ROUND(AVG(TASK_PRGRT)) FROM TASK T WHERE T.PROJ_NO = A.PROJ_NO) AS projPrgrt
, CASE WHEN SYSDATE < A.PROJ_BGNG_DT THEN 0 WHEN SYSDATE > A.PROJ_END_DT THEN 100 ELSE ROUND((SYSDATE - A.PROJ_BGNG_DT) / (A.PROJ_END_DT - A.PROJ_BGNG_DT) * 100) END AS TIME_PRGRT
FROM PROJECT A LEFT OUTER JOIN PROJECT_PARTICIPANT B ON A.PROJ_NO=B.PROJ_NO WHERE B.EMP_ID=#{empId}

SELECT A.*
FROM PROJECT_PARTICIPANT A
WHERE A.PROJ_NO = #{projNo}

SELECT A.* /* 1. 업무 진척도: 하위 작업(TASK)들의 평균 진행률 */ , (SELECT ROUND(AVG(TASK_PRGRT)) FROM TASK T WHERE T.PROJ_NO = A.PROJ_NO) AS projPrgrt
/* 2. 기간 진척도: 전체 기간 중 오늘이 차지하는 비중 (CDATA로 기호 보호) */
, CASE WHEN SYSDATE < A.PROJ_BGNG_DT THEN 0 WHEN SYSDATE > A.PROJ_END_DT THEN 100 ELSE ROUND((SYSDATE - A.PROJ_BGNG_DT) / (A.PROJ_END_DT - A.PROJ_BGNG_DT) * 100) END AS TIME_PRGRT
FROM PROJECT A WHERE A.PROJ_NO = #{projNo}

mapper.update:
UPDATE TASK
SET TASK_STTS = '지연'
WHERE TASK_NO = #{taskNo}
